import{_ as t}from"./chunks/pnp_four_view_strict_success_sequence.BINevMMP.js";import{_ as a,o as i,c as o,af as n}from"./chunks/framework.BSym9njW.js";const r="/hello-rocm/assets/every-embodied-flow-en.RuOt5yvr.webp",b=JSON.parse('{"title":"Every Embodied: Replicating Embodied Intelligence Policies on ROCm","description":"","frontmatter":{},"headers":[],"relativePath":"05-amd-yes/every-embodied.md","filePath":"en/05-amd-yes/every-embodied.md","lastUpdated":1783958531000}'),s={name:"05-amd-yes/every-embodied.md"};function l(d,e,c,m,h,g){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="every-embodied-replicating-embodied-intelligence-policies-on-rocm" tabindex="-1">Every Embodied: Replicating Embodied Intelligence Policies on ROCm <a class="header-anchor" href="#every-embodied-replicating-embodied-intelligence-policies-on-rocm" aria-label="Permalink to &quot;Every Embodied: Replicating Embodied Intelligence Policies on ROCm&quot;">​</a></h1><div align="center"><p><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/AMD-ROCm-ED1C24" alt="AMD"></a><a href="https://github.com/datawhalechina/every-embodied" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Datawhale-Every%20Embodied-1F6FEB" alt="Every Embodied"></a></p></div><div align="center"><img src="'+r+'" alt="every-embodied" width="95%"></div><p>ROCm isn&#39;t just for deploying and fine-tuning language models – it can also handle vision encoding, policy training, action inference, and batch evaluation in embodied intelligence. Datawhale&#39;s <a href="https://github.com/datawhalechina/every-embodied" target="_blank" rel="noreferrer">Every Embodied</a> project provides a set of MuJoCo desktop manipulation experiments and replicates the training and debugging workflows for ACT, SmolVLA, Pi0, and Pi0.5 on AMD Ryzen AI MAX+ 395 / ROCm environments.</p><p>This page focuses on the Every Embodied ROCm replication work. Complete code, notebooks, environment commands, experimental results, and troubleshooting processes are maintained in the Every Embodied repository to avoid duplicating the same material across two repositories.</p><div align="center"><img src="'+t+'" alt="MuJoCo four-view cup grasping strict success sequence" width="95%"><p>MuJoCo four-view cup grasping strict success sequence</p></div><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>This series doesn&#39;t just show a single success video – it covers the complete closed loop from data to physical success criteria:</p><ol><li>Perform keyboard teleoperation in MuJoCo, recording multi-view images, robot states, and action trajectories.</li><li>Organize data into LeRobot format and verify episodes, timestamps, action dimensions, and normalization statistics.</li><li>Train ACT, SmolVLA, Pi0/Pi0.5 on ROCm, recording VRAM usage, temperature, loss, and checkpoints.</li><li>Deploy policies back to the simulation environment for closed-loop inference and batch evaluation with randomized positions and different colored cups.</li><li>Use strict physical success conditions composed of &quot;lift, carry, release, final placement&quot; rather than just loss or single-frame visuals.</li><li>Diagnose failure causes through teacher-forced replay, open-loop action traces, DAgger/recovery data, weighted sampling, and action representation audits.</li></ol><h2 id="models-and-experimental-content" tabindex="-1">Models and Experimental Content <a class="header-anchor" href="#models-and-experimental-content" aria-label="Permalink to &quot;Models and Experimental Content&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Model</th><th style="text-align:left;">Main Content in Series</th><th style="text-align:left;">Current Reading Focus</th><th style="text-align:left;">Notebook</th></tr></thead><tbody><tr><td style="text-align:left;">ACT</td><td style="text-align:left;">Single and randomized data training, joint action diagnostics, DAgger/recovery data</td><td style="text-align:left;">Why small-data imitation learning accumulates errors in closed loop</td><td style="text-align:left;"><a href="https://github.com/datawhalechina/every-embodied/blob/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks/08_act_training_rocm.ipynb" target="_blank" rel="noreferrer">ACT ROCm Training</a></td></tr><tr><td style="text-align:left;">SmolVLA</td><td style="text-align:left;">Pretrained weight loading, red/blue cup sampling imbalance, weighted sampling and random position evaluation</td><td style="text-align:left;">How data coverage and sampling distribution affect generalization</td><td style="text-align:left;"><a href="https://github.com/datawhalechina/every-embodied/blob/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks/09_smolvla_training_rocm.ipynb" target="_blank" rel="noreferrer">SmolVLA ROCm Training</a></td></tr><tr><td style="text-align:left;">Pi0</td><td style="text-align:left;">Permission and weight smoke tests, separate evaluation of raw policy vs. learned auxiliary heads</td><td style="text-align:left;">Not misreporting scripted finisher success as end-to-end VLA success</td><td style="text-align:left;"><a href="https://github.com/datawhalechina/every-embodied/blob/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks/10_pi0_training_rocm.ipynb" target="_blank" rel="noreferrer">Pi0 ROCm Training</a> · <a href="https://github.com/datawhalechina/every-embodied/blob/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks/12_pi0_strict_input_end_to_end.ipynb" target="_blank" rel="noreferrer">Strict End-to-End Diagnostics</a></td></tr><tr><td style="text-align:left;">Pi0.5</td><td style="text-align:left;">LeRobot v3 data specification, EEF-delta action representation, chunk alignment and recovery training</td><td style="text-align:left;">Why action direction, execution window, and closed-loop correction are more critical than simply increasing training steps</td><td style="text-align:left;"><a href="https://github.com/datawhalechina/every-embodied/blob/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks/13_pi05_random_position_eef_delta.ipynb" target="_blank" rel="noreferrer">Pi0.5 Random Position &amp; EEF-delta</a></td></tr></tbody></table><p>The series clearly distinguishes three result categories: <strong>raw policy</strong>, <strong>learnable auxiliary modules</strong> using only vision/language/proprioceptive state, and <strong>diagnostic scaffolding</strong> that injects target positions or hand-written stage rules. These serve different purposes and their success rates cannot be compared directly.</p><h2 id="project-resources" tabindex="-1">Project Resources <a class="header-anchor" href="#project-resources" aria-label="Permalink to &quot;Project Resources&quot;">​</a></h2><ul><li><a href="https://github.com/datawhalechina/every-embodied#readme" target="_blank" rel="noreferrer">Every Embodied Project README</a></li><li><a href="https://github.com/datawhalechina/every-embodied/tree/main/16-%E4%B8%93%E9%A2%98%E7%BB%84%E9%98%9F%E5%AD%A6%E4%B9%A0/04-AMD-ROCm%E7%AD%96%E7%95%A5%E5%A4%8D%E5%88%BB%E4%B8%93%E9%A2%98/notebooks" target="_blank" rel="noreferrer">Every Embodied ROCm Policy Replication Notebooks</a></li></ul><p>Start with the device-check and physical-success-evaluation notebooks before data collection, training, and deployment. This verifies that the evaluator identifies success correctly before long training runs expose action-direction, data-format, or success-condition errors.</p><h2 id="hardware-and-software-notes" tabindex="-1">Hardware and Software Notes <a class="header-anchor" href="#hardware-and-software-notes" aria-label="Permalink to &quot;Hardware and Software Notes&quot;">​</a></h2><p>The series primarily validates on AMD Ryzen AI MAX+ 395, using Ubuntu, ROCm, PyTorch, LeRobot, and MuJoCo. Ryzen AI MAX+ 395 uses a unified memory architecture where system memory and GPU available memory are shared, so you still need to monitor GPU allocation, system memory, and temperature during training – you can&#39;t treat all unified memory as unconditionally usable dedicated VRAM.</p><p>Compatibility between different ROCm, PyTorch, and LeRobot versions will vary. Before starting replication, refer to the device check notebooks in the series, locked versions, and the current <a href="https://rocm.docs.amd.com/en/latest/compatibility/compatibility-matrix.html" target="_blank" rel="noreferrer">ROCm compatibility documentation</a>.</p><h2 id="why-it-s-worth-trying" tabindex="-1">Why It&#39;s Worth Trying <a class="header-anchor" href="#why-it-s-worth-trying" aria-label="Permalink to &quot;Why It&#39;s Worth Trying&quot;">​</a></h2><p>After migrating embodied intelligence policies to ROCm, the truly difficult part usually isn&#39;t changing <code>cuda</code> strings to <code>hip</code>, but aligning model dependencies, data formats, action semantics, execution frequency, and physical evaluation protocols simultaneously. Every Embodied preserves these failure cases and repair tools together, so you can directly see what engineering steps are still missing between &quot;loss looks normal&quot; and &quot;actually completing the task in simulation.&quot;</p>',20)])])}const y=a(s,[["render",l]]);export{b as __pageData,y as default};
